            contacts: '📧',
            settings: '⚙️',
            courses: '📚',
            progress: '📈',
            profile: '👤',
            analytics: '📈',
            messages: '💬'
        };
        return icons[tab] || '📄';
    };

    const getTabTitle = (tab) => {
        const titles = {
            overview: 'Overview',
            users: 'User Management',
            applications: 'Application Management',
            contacts: 'Contact Management',
            settings: currentUser?.role === 'admin' ? 'System Settings' : 'Settings',
            courses: 'My Courses',
            progress: 'Learning Progress',
            profile: 'Profile Settings',
            analytics: 'Course Analytics',
            messages: 'Messages & Communications'
        };
        return titles[tab] || 'Dashboard';
    };

    const getQuickStats = () => {
        if (currentUser?.role === 'admin') {
            return [
                { value: pendingUsers.length, label: 'Pending Users' },
                { value: applicationSubmissions.filter(app => app.status === 'pending').length, label: 'New Applications' },
                { value: contactSubmissions.filter(contact => contact.status === 'pending').length, label: 'Unread Messages' }
            ];
        }
        // Add stats for other roles
        return [];
    };

    const getQuickActions = () => {
        if (currentUser?.role === 'admin') {
            return [
                { icon: '👤', label: 'Create New User', onClick: () => setShowCreateUserForm(true) },
                { icon: '📧', label: 'Send Announcement', onClick: () => {} },
                { icon: '📊', label: 'Generate Report', onClick: () => {} },
                { icon: '⚙️', label: 'System Settings', onClick: () => setActiveTab('settings') }
            ];
        }
        // Add actions for other roles
        return [];
    };
    
